'use client';

import { useState } from 'react';
import { Module } from '@/types/course';
import { ResourceList } from './ResourceList';

interface ModuleCardProps {
  module: Module;
  language: string;
}

export function ModuleCard({ module, language }: ModuleCardProps) {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <div className="border border-gray-200 rounded-xl overflow-hidden hover:border-orange-200 transition-colors">
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="w-full px-5 py-4 flex items-center justify-between text-left hover:bg-orange-50/50 transition-colors"
      >
        <div className="flex items-center gap-3">
          <span className="flex-shrink-0 w-8 h-8 bg-orange-100 text-orange-700 rounded-full flex items-center justify-center text-sm font-bold">
            {module.week}
          </span>
          <div>
            <h3 className="font-semibold text-gray-900">
              {language === 'hi' ? module.titleHindi || module.title : module.title}
            </h3>
            <p className="text-xs text-gray-500 mt-0.5">
              {module.topics.length} topics · {module.estimatedHours}h
            </p>
          </div>
        </div>
        <svg
          className={'w-5 h-5 text-gray-400 transition-transform ' + (isOpen ? 'rotate-180' : '')}
          fill="none"
          viewBox="0 0 24 24"
          stroke="currentColor"
        >
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
        </svg>
      </button>

      {isOpen && (
        <div className="px-5 pb-4 border-t border-gray-100">
          <div className="mt-3 mb-4">
            <div className="flex flex-wrap gap-2">
              {module.topics.map((topic, i) => (
                <span key={i} className="px-2.5 py-1 bg-gray-100 text-gray-700 rounded-md text-xs">
                  {topic}
                </span>
              ))}
            </div>
          </div>

          {module.resources.length > 0 && (
            <ResourceList resources={module.resources} />
          )}
        </div>
      )}
    </div>
  );
}
